---- MODULE MemoryAllocator ----
EXTENDS Integers, Sequences, FiniteSets

CONSTANTS N, Pages, Client

VARIABLES free, allocated

Init == /\ free = Pages
        /\ allocated = [c \in Client |-> {}]

Next == \/ /\ free # {}
          /\ free' = free \ {p}
             /\ allocated' = [c \in Client |-> IF c = client THEN allocated[c] \cup {p}

          /\ client \in Client
             /\ p \in free
          \/ /\ allocated[client] # {}
             /\ free' = free \cup {p}
                /\ allocated' = [c \in Client |-> IF c = client THEN allocated[c] \setminus {p}

             /\ client \in Client
                /\ p \in allocated[client]

TypeOK == /\ free \subseteq Pages
          /\ allocated \in [Client -> SUBSET Pages]
          /\ \A c \in Client: allocated[c] \subseteq Pages
          /\ \A c1, c2 \in Client: c1 # c2 => allocated[c1] \cap allocated[c2] = {}

Spec == Init /\ [][Next]_<<free, allocated>>

====

---- MODULE Dekker ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES turn, wants

Init == /\ turn \in {0, 1}
        /\ wants \in SUBSET {0, 1}
        /\ turn \in {0, 1}
        /\ wants \subseteq {0, 1}

Next == \/ /\ turn' = 0
          /\ wants' = {0}
        \/ /\ turn' = 1
          /\ wants' = {1}
        \/ /\ turn' = turn
          /\ wants' = wants

Spec == Init /\ [][Next]_<<turn, wants>>

====
